using namespace std;

const int N = 1000005;

int n;
string s[N];

void solve(){
    int a, b, c;
    cin >> n >> a >> b >> c;
    if(s[a][b] != s[a][c] || s[a][b] != s[b][c]) {
        cout << -1 << endl;
        return;
    }
    if(a == 1 || b == 1 || c == 1) {
        cout << 1 << endl;
        cout << 1 << " " << (a == 1 ? b : a) << endl;
        return;
    }
    cout << 2 << endl;
    cout << 1 << " " << c << endl;
    cout << c << " " << 1 << endl;
}

int main(){
    cin >> n;
    for(int i = 1; i <= n; i++) {
        cin >> s[i];
    }
    solve();
    return 0;
}
